def count_terminating_decimals(n):
    count = 0
    for k in range(1, n + 1):
        if all(p in [2, 5] for p in set(prime_factors(k))):
            count += 1
    return count

def prime_factors(n):
    i = 2
    factors = []
    while i * i <= n:
        if n % i:
            i += 1
        else:
            n //= i
            factors.append(i)
    if n > 1:
        factors.append(n)
    return factors

def find_smallest_n():
